#include <iostream>
using namespace std;
int main()
{
    int a[105],n,k[105];
    cin>>n;
    for(int i=0;i<n;i++)
    {
    	cin>>a[i];
    }
    cout<<"0 ";
    for(int j=1;j<n;j++)
    {
    	k[j]=0;
    	for(int c=j-1;c>=0;c--)
    	{
    		if(a[c]<a[j])k[j]++;
    	}
		cout<<k[j]<<" ";
    }
    return 0;
}
